SELECT id, elder_id, child_id, score, comment, review_month, type, status, completed_at, attitude, response, quality, satisfaction, suggestion, created_at
FROM service_review
WHERE id = #{id}

SELECT id, elder_id, child_id, score, comment, review_month, type, status, completed_at, attitude, response, quality, satisfaction, suggestion, created_at
FROM service_review
WHERE elder_id = #{elderId} AND review_month = #{reviewMonth}
